from Crypto.Util.number import bytes_to_long, long_to_bytes

def extended_gcd(a, b):
    """
    Compute the extended GCD of a and b.
    Returns gcd(a, b), and coefficients x and y such that ax + by = gcd(a, b)
    """
    if a == 0:
        return b, 0, 1
    else:
        gcd, x1, y1 = extended_gcd(b % a, a)
        x = y1 - (b // a) * x1
        y = x1
        return gcd, x, y

def common_modulus_attack(N, e1, e2, c1, c2):
    """
    Perform the common modulus attack on RSA.
    Given two ciphertexts c1 and c2, encrypted under exponents e1 and e2 respectively,
    with the same modulus N, recover the plaintext message m.
    """
    gcd, s, t = extended_gcd(e1, e2)
    if gcd != 1:
        raise Exception("Exponents e1 and e2 are not co-prime.")

    # Handle negative coefficients
    if s < 0:
        s = -s
        c1_inv = pow(c1, -1, N)
        c1_part = pow(c1_inv, s, N)
    else:
        c1_part = pow(c1, s, N)

    if t < 0:
        t = -t
        c2_inv = pow(c2, -1, N)
        c2_part = pow(c2_inv, t, N)
    else:
        c2_part = pow(c2, t, N)

    # Recover the plaintext
    m = (c1_part * c2_part) % N
    return m

